const inp = $input.item.json;
const rawText = Array.isArray(inp.content) ? inp.content[0].text : JSON.stringify(inp);
let raw = rawText.trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e1) {
  const m = raw.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  if (m) {
    try { parsed = JSON.parse(m[1].trim()); }
    catch(e2) { throw new Error('Claude block not JSON: ' + m[1].substring(0,150)); }
  } else {
    const s = raw.indexOf('{'); const e = raw.lastIndexOf('}');
    if (s !== -1 && e > s) {
      try { parsed = JSON.parse(raw.substring(s, e+1)); }
      catch(e3) { throw new Error('No valid JSON in Claude response: ' + raw.substring(0,150)); }
    } else {
      throw new Error('No JSON object in Claude response: ' + raw.substring(0,150));
    }
  }
}
const negData = $('C1 Получить данные отклика').first().json;
return {
  nid: negData.id?.toString(),
  score: parsed.score,
  verdict: parsed.verdict,
  comment: parsed.comment,
  rejectionText: parsed.rejection_text || '',
  firstQuestion: parsed.first_question || '',
  candidateName: negData.resume?.last_name + ' ' + negData.resume?.first_name,
  resumeSummary: parsed.comment,
  vacancyId: negData.vacancy?.id?.toString(),
  vacancyName: negData.vacancy?.name || ''
};

const staticData = $getWorkflowStaticData('global');
if (!staticData.negotiations) staticData.negotiations = {};

const nid = $json.nid;
staticData.negotiations[nid] = {
  nid,
  vacancyId: $json.vacancyId,
  vacancyName: $json.vacancyName,
  candidateName: $json.candidateName,
  resumeScore: $json.score,
  resumeSummary: $json.resumeSummary,
  state: 'screening',
  currentQuestion: 1,
  totalQuestions: 3,
  questionsAsked: [$json.firstQuestion],
  answersGiven: []
};

return { nid, firstQuestion: $json.firstQuestion };

const staticData = $getWorkflowStaticData('global');
const nid = $json.body?.object?.id?.toString();
const messageText = $json.body?.message?.text || '';

const state = staticData.negotiations?.[nid] || null;

if (!state) {
  return { error: 'Negotiation not found in static data', nid };
}

return {
  nid,
  messageText,
  candidateName: state.candidateName,
  vacancyId: state.vacancyId,
  vacancyName: state.vacancyName,
  resumeScore: state.resumeScore,
  currentQuestion: state.currentQuestion,
  totalQuestions: state.totalQuestions,
  questionsAsked: state.questionsAsked,
  answersGiven: state.answersGiven,
  isLastQuestion: state.currentQuestion >= state.totalQuestions
};

const staticData = $getWorkflowStaticData('global');
const nid = $json.nid;

if (staticData.negotiations?.[nid]) {
  staticData.negotiations[nid].answersGiven.push($json.messageText);
}

return $json;

