const staticData = $getWorkflowStaticData('global');
const nid = $('D1 Загрузить контекст').first().json.nid;

if (nid && staticData.negotiations) {
  delete staticData.negotiations[nid];
}

return { cleared: true, nid };

const staticData = $getWorkflowStaticData('global');
const negotiations = $('E2 Отклики за 24ч').first().json?.items || [];
const processedIds = new Set(Object.keys(staticData.negotiations || {}));

const cutoff = Date.now() - 24 * 60 * 60 * 1000;

const unprocessed = negotiations.filter(n => {
  const updatedAt = new Date(n.updated_at).getTime();
  return !processedIds.has(n.id?.toString()) && n.state?.id === 'response' && updatedAt > cutoff;
});

return { unprocessedCount: unprocessed.length, processedCount: processedIds.size, totalActive: negotiations.length, unprocessed };

