const staticData = $getWorkflowStaticData('global');
const chatId = $json.message?.chat?.id?.toString();
const text = $json.message?.text || '';

if (!staticData.briefs) staticData.briefs = {};

let state = staticData.briefs[chatId];

if (!state || state.step === 'done') {
  state = { step: 'init', chatId, originalRequest: text, answers: [], currentQuestion: 0, totalQuestions: 4 };
} else {
  state.answers.push(text);
  state.currentQuestion++;
}

staticData.briefs[chatId] = state;

return { chatId, step: state.step, originalRequest: state.originalRequest, currentQuestion: state.currentQuestion, totalQuestions: state.totalQuestions, answers: state.answers, allAnswered: state.currentQuestion >= state.totalQuestions };
